package com.hugogonzalez.polentracker.collector.source; import com.hugogonzalez.polentracker.domain.PollenSourceType; import org.springframework.stereotype.Component; import java.util.*;
@Component public class PollenSourceAdapterFactory {private final Map<PollenSourceType,PollenSourceAdapter> adapters; public PollenSourceAdapterFactory(List<PollenSourceAdapter> values){Map<PollenSourceType,PollenSourceAdapter> map=new EnumMap<>(PollenSourceType.class); values.forEach(a->map.put(a.supportedSource(),a)); adapters=Map.copyOf(map);} public PollenSourceAdapter get(PollenSourceType type){PollenSourceAdapter adapter=adapters.get(type); if(adapter==null)throw new IllegalArgumentException("Unsupported source: "+type); return adapter;}}
